{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/AnnotationConstructorTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class AnnotationConstructorTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Nested
    inner class `Annotations before constructor with ktlint_official` {
        @Test
        fun `Given a single annotation before constructor with ktlint_official style, then wrap it`() {
            val code =
                """
                class Foo @Inject internal constructor()
                """.trimIndent()
            val formattedCode =
                """
                class Foo
                    @Inject
                    internal constructor()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasLintViolation(1, 11, "Annotation(s) before constructor should be on a separate line")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given multiple annotations before constructor with ktlint_official style, then wrap them`() {
            val code =
                """
                data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            val formattedCode =
                """
                data class Foo
                    @Bar1
                    @Bar2("bar")
                    @Bar3
                    @Bar4
                    constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .addAdditionalRuleProvider { IndentationRule() }
                .hasLintViolations(
                    LintViolation(1, 16, "Annotations before constructor should be on separate lines"),
                    LintViolation(1, 22, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                    LintViolation(1, 35, "Annotations before constructor should be on separate lines"),
                    LintViolation(1, 41, "Annotations before constructor should be on separate lines"),
                    LintViolation(1, 47, "Annotation(s) before constructor should be on a separate line"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given annotations before constructor without ktlint_official style, then allow single annotation`() {
            val code =
                """
                class Foo @Inject internal constructor()
