import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class AnnotationConstructorKtlintOfficialTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Nested
    inner class `Annotations before constructor with ktlint_official` {
        @Test
        fun `Given a single annotation before constructor with ktlint_official style, then wrap it`() {
            val code =
                """
                class Foo @Inject internal constructor()
                """.trimIndent()
            val formattedCode =
                """
                class Foo
                    @Inject
                    internal constructor()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasLintViolation(1, 28, "Annotation(s) before constructor should be on a separate line")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given multiple annotations before constructor with ktlint_official style, then wrap them`() {
            val code =
                """
                data class Foo @Bar1 @Bar2 @Bar3 constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            val formattedCode =
                """
                data class Foo
                    @Bar1
                    @Bar2
                    @Bar3
                    constructor(private val foobar: Int) {
                    fun foo(): String = "foo"
                }
                """.trimIndent()
            annotationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .addAdditionalRuleProvider { IndentationRule() }
                .hasLintViolations(
                    LintViolation(1, 22, "Annotations before constructor should be on separate lines"),
                    LintViolation(1, 28, "Annotations before constructor should be on separate lines"),
                    LintViolation(1, 34, "Annotation(s) before constructor should be on a separate line"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given annotations before constructor without ktlint_official style, then allow single annotation`() {
            val code =
                """
                class Foo @Inject internal constructor()
                """.trimIndent()
            // Without ktlint_official, single annotation before constructor is allowed
            annotationRuleAssertThat(code).hasNoLintViolations()
        }
    }

    @Nested
    inner class `Annotations on type projections` {
        @Test
        fun `Given a single annotation without parameter on type projection, then allow it`() {
            val code =
                """
                val foo1: List<@Foo String> = emptyList()
                val foo2 = emptyList<@Foo String>()
                val foo3: Map<@Foo String, @Foo String> = emptyMap()
                val foo4 = emptyMap<@Foo String, @Foo String>()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .hasNoLintViolations()
        }

        @Test
        fun `Given multiple annotations without parameters on type projection, then wrap them`() {
            val code =
                """
                val fooBar: List<@Foo @Bar String> = emptyList()
                """.trimIndent()
            val formattedCode =
                """
                val fooBar: List<
                    @Foo @Bar
                    String
                > = emptyList()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .addAdditionalRuleProvider { IndentationRule() }
                .addAdditionalRuleProvider { WrappingRule() }
                .hasLintViolations(
                    LintViolation(1, 17, "Expected newline after '<'"),
                    LintViolation(1, 28, "Multiple annotations should not be placed on the same line as the annotated construct"),
                    LintViolation(1, 34, "Expected newline before '>'"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a single annotation with parameter on type projection, then wrap it`() {
            val code =
                """
                val fooBar: List<@Bar("bar") String> = emptyList()
                """.trimIndent()
            val formattedCode =
                """
                val fooBar: List<
                    @Bar("bar")
                    String
                > = emptyList()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .addAdditionalRuleProvider { IndentationRule() }
                .hasLintViolations(
                    LintViolation(1, 17, "Expected newline after '<'"),
                    LintViolation(1, 18, "Annotation with parameter(s) should be placed on a separate line prior to the annotated construct"),
                    LintViolation(1, 36, "Expected newline before '>'"),
                ).isFormattedAs(formattedCode)
        }

        @Test
        fun `Given multiple type projections with mixed annotations, then wrap appropriately`() {
            val code =
                """
                val fooBar: FooBar<String, @Foo String, @Foo @Bar String, @Bar("bar") @Foo String> = FooBar()
                """.trimIndent()
            val formattedCode =
                """
                val fooBar: FooBar<
                    String,
                    @Foo String,
                    @Foo @Bar
                    String,
                    @Bar("bar")
                    @Foo
                    String
                    > = FooBar()
                """.trimIndent()
            annotationRuleAssertThat(code)
                .addAdditionalRuleProvider { IndentationRule() }
                .addAdditionalRuleProvider { WrappingRule() }
                .hasLintViolations(
