                    //   1. Multiple annotations on the same type projection
                    //   2. A single annotation with parameters
                    // But following is allowed:
                    //   var foo: List<@Foo String>  // single annotation without parameter
                    //   var foo: List<@[Foo Bar] String>  // annotation array
                    val shouldWrapTypeProjectionAnnotations =
                        node.isFollowedByOtherAnnotationEntryOnTheSameLine() ||
                            node.isPrecededByOtherAnnotationEntryOnTheSameLine() ||
                            (node.isAnnotationEntryWithValueArgumentList() && !node.isFollowedByOtherAnnotationEntryOnTheSameLine() && !node.isPrecededByOtherAnnotationEntryOnTheSameLine())

                    if (shouldWrapTypeProjectionAnnotations) {
                        if (node.isFollowedByOtherAnnotationEntryOnTheSameLine() &&
